class NetworkMap{constructor(){this.cy=null,this.data={taxonomy:null,companies:[],profiling:{}},this.selections={groups:new Set,intents:new Set,companies:new Set},this.init()}async init(){try{await this.loadData(),this.initCytoscape(),this.renderSidebar(),this.setupControls(),document.getElementById("loader").style.display="none"}catch(t){console.error("NetworkMap initialization failed:",t)}}async loadData(){const[t,e,n,i]=await Promise.all([fetch("taxonomy.json"),fetch("live_companies.json"),fetch("temp_companies.json"),fetch("company_profiling_data.json")]);this.data.taxonomy=await t.json();const s=await e.json(),o=await n.json(),a=await i.json(),c={};[...o.results||[],...s.results||[]].forEach(t=>{c[t.id]=t}),this.data.companies=Object.values(c),this.data.profiling=a.profiles,console.log("NetworkMap: Data loaded",{companies:this.data.companies.length,groups:this.data.taxonomy.groups.length})}initCytoscape(){this.cy=cytoscape({container:document.getElementById("cy"),style:[{selector:"node",style:{label:"data(label)","text-valign":"center","text-halign":"center",color:"#fff","font-size":"12px","font-family":"Inter, sans-serif","font-weight":"600","text-wrap":"wrap","text-max-width":"80px",width:"mapData(weight, 0, 100, 40, 80)",height:"mapData(weight, 0, 100, 40, 80)","background-color":"#475569","border-width":2,"border-color":"#1e293b","transition-property":"background-color, line-color, target-arrow-color, width, height","transition-duration":"0.3s"}},{selector:'node[type="group"]',style:{"background-color":"#6366f1","font-size":"14px",width:100,height:100}},{selector:'node[type="intent"]',style:{"background-color":"#3b82f6",width:70,height:70}},{selector:'node[type="company"]',style:{"background-color":"#10b981",width:60,height:60,"font-size":"10px"}},{selector:"edge",style:{width:2,"line-color":"#cbd5e1","curve-style":"bezier",opacity:.5,"target-arrow-shape":"triangle","target-arrow-color":"#cbd5e1"}},{selector:'edge[type="semantic"]',style:{"line-style":"dashed","line-color":"#fbbf24","target-arrow-color":"#fbbf24"}}],layout:{name:"cose",animate:!0}}),this.cy.on("tap","node",t=>{const e=t.target;if("company"===e.data("type")){const t=e.id(),n=this.data.companies.find(e=>e.id===t);n&&window.LkiModal&&window.LkiModal.open(n)}})}renderSidebar(){const t=document.getElementById("category-list");t.innerHTML="",this.data.taxonomy.groups.forEach(e=>{const n=document.createElement("div");n.className="selection-item",n.dataset.id=e.id;const i=this.data.companies.filter(t=>{const n=this.data.profiling[t.id];return n?.core?.fits_for?.[e.id]>20}).length;n.innerHTML=`\n                <span class="item-name">${e.name}</span>\n                <span class="item-count">${i}</span>\n            `,n.onclick=()=>this.toggleGroup(e.id),t.appendChild(n)})}toggleGroup(t){const e=document.querySelector(`#category-list .selection-item[data-id="${t}"]`);if(this.selections.groups.has(t))this.selections.groups.delete(t),e.classList.remove("active"),this.removeNode(t);else{this.selections.groups.add(t),e.classList.add("active");const n=this.data.taxonomy.groups.find(e=>e.id===t);this.addNode({id:t,label:n.name,type:"group",weight:100})}this.updateIntentList(),this.runLayout()}updateIntentList(){const t=document.getElementById("intent-section"),e=document.getElementById("intent-list");if(e.innerHTML="",0===this.selections.groups.size)return void(t.style.display="none");t.style.display="block";const n=new Set;this.selections.groups.forEach(t=>{this.data.taxonomy.groups.find(e=>e.id===t).codes.forEach(t=>n.add(t))}),n.forEach(t=>{const n=this.data.taxonomy.intents[t];if(!n)return;const i=document.createElement("div");i.className="selection-item"+(this.selections.intents.has(t)?" active":""),i.dataset.id=t;const s=this.data.companies.filter(e=>{const i=(e.tags||"").toLowerCase(),s=n.fi.toLowerCase();return i.includes(s)||e.intent_codes&&e.intent_codes.includes(t)}).length;i.innerHTML=`\n                <span class="item-name">${n.fi}</span>\n                <span class="item-count">${s}</span>\n            `,i.onclick=()=>this.toggleIntent(t),e.appendChild(i)})}toggleIntent(t){const e=document.querySelector(`#intent-list .selection-item[data-id="${t}"]`);if(this.selections.intents.has(t))this.selections.intents.delete(t),e.classList.remove("active"),this.removeNode(t);else{this.selections.intents.add(t),e.classList.add("active");const n=this.data.taxonomy.intents[t];this.addNode({id:t,label:n.fi,type:"intent",weight:80}),this.selections.groups.forEach(e=>{this.data.taxonomy.groups.find(t=>t.id===e).codes.includes(t)&&this.addEdge(e,t)})}this.updateCompanyList(),this.runLayout()}updateCompanyList(){const t=document.getElementById("company-section"),e=document.getElementById("company-list");if(e.innerHTML="",0===this.selections.intents.size)return void(t.style.display="none");t.style.display="block";let n=this.data.companies.filter(t=>Array.from(this.selections.intents).some(e=>{const n=this.data.taxonomy.intents[e],i=(t.tags||"").toLowerCase(),s=n.fi.toLowerCase();return i.includes(s)||t.intent_codes&&t.intent_codes.includes(e)}));n.sort((t,e)=>{const n=(t.package||"").toLowerCase(),i=(e.package||"").toLowerCase();return n.includes("premium")&&!i.includes("premium")?-1:!n.includes("premium")&&i.includes("premium")?1:0}),n.slice(0,20).forEach(t=>{const n=document.createElement("div");n.className="selection-item"+(this.selections.companies.has(t.id)?" active":""),n.dataset.id=t.id,n.innerHTML=`\n                <span class="item-name">${t.nimi}</span>\n            `,n.onclick=()=>this.toggleCompany(t.id),e.appendChild(n)})}toggleCompany(t){const e=document.querySelector(`#company-list .selection-item[data-id="${t}"]`);if(this.selections.companies.has(t))this.selections.companies.delete(t),e&&e.classList.remove("active"),this.removeNode(t);else{this.selections.companies.add(t),e&&e.classList.add("active");const n=this.data.companies.find(e=>e.id===t);this.addNode({id:t,label:n.nimi,type:"company",weight:60}),this.selections.intents.forEach(e=>{const i=this.data.taxonomy.intents[e],s=(n.tags||"").toLowerCase(),o=i.fi.toLowerCase();(s.includes(o)||n.intent_codes&&n.intent_codes.includes(e))&&this.addEdge(e,t)}),this.selections.companies.forEach(e=>{if(e===t)return;const n=this.data.profiling[t];(n?.categories?.events_and_celebrations?.collaborated_with?.includes(e)||n?.core?.paired_with_by_context?.general?.includes(e))&&this.addEdge(t,e,"semantic")})}this.runLayout()}addNode(t){0===this.cy.getElementById(t.id).length&&this.cy.add({group:"nodes",data:t})}removeNode(t){this.cy.remove(this.cy.getElementById(t))}addEdge(t,e,n="normal"){const i=`e-${t}-${e}`;0===this.cy.getElementById(i).length&&this.cy.add({group:"edges",data:{id:i,source:t,target:e,type:n}})}runLayout(){this.cy.layout({name:"cose",animate:!0,randomize:!1,componentSpacing:100,nodeRepulsion:4e3,edgeElasticity:100,nestingFactor:5}).run()}setupControls(){document.getElementById("zoom-in").onclick=()=>this.cy.zoom(1.2*this.cy.zoom()),document.getElementById("zoom-out").onclick=()=>this.cy.zoom(.8*this.cy.zoom()),document.getElementById("fit-view").onclick=()=>this.cy.fit(),document.getElementById("refresh-layout").onclick=()=>this.runLayout()}}document.addEventListener("DOMContentLoaded",()=>{window.networkMap=new NetworkMap,window.i18n&&window.i18n.translatePage()});